import vex
from beeai import Agent, EventType

# Initialize Vex client with government workspace
vex_client = vex.Client(api_key="gov-fedramp-key")

@vex_client.on_event("beeai.agent")
def audit_agent_events(event):
    if event['type'] == EventType.TOOL_CALL:
        vex_client.log_audit({
            'agent_id': event['agent_id'],
            'tool': event['tool_name'],
            'input': event['input'],
            'classification': classify_data(event['input'])
        })

# Register with BeeAI agent
agent = Agent(name="GovBenefitsBot")
agent.add_event_listener(vex_client)

from vex.policies import DataClassificationPolicy
import re

class ClassifiedDataPolicy(DataClassificationPolicy):
    CLASSIFIED_PATTERNS = [
        r'\b(TS|SCI|NOFORN|SAP)\b',
        r'\b[0-9]{4}-[0-9]{4}-[0-9]{4}-[0-9]{4}\b',  # SSN
        r'\b[A-Z]{3}-\d{6}\b'  # DoD ID
    ]

    def validate(self, tool_input: str) -> bool:
        for pattern in self.CLASSIFIED_PATTERNS:
            if re.search(pattern, tool_input):
                raise vex.Violation(
                    'CLASSIFIED_DATA_DETECTED',
                    'Input contains classified indicators',
                    severity='critical'
                )
                return False
        return True

# Apply to BeeAI tools
agent.tools.validate_with(ClassifiedDataPolicy())

import vex
from beeai import MemoryManager

@vex_client.policy("gov.memory-limit")
def enforce_memory_limits(memory_event):
    session_memory = memory_event['current_size']
    if session_memory > 100 * 1024 * 1024:  # 100MB limit
        raise vex.Violation(
            'MEMORY_EXCEEDED',
            f'Session memory {session_memory/1024/1024:.1f}MB exceeds FISMA limits',
            remediation='truncate_conversation'
        )

@vex_client.on_event("beeai.memory")
def monitor_granite_outputs(event):
    if not event['output'].get('explanation'):
        raise vex.Violation(
            'NON_EXPLAINABLE',
            'Granite output missing required explanation chain',
            policy='executive-order-ai'
        )

# Install memory manager
agent.memory = MemoryManager(max_size='100mb')
agent.add_event_listener(vex_client)
